class Solution {
public:
    int minDays(int n) {
        queue<int> q;
        q.push(n);
        int days = 0;
        unordered_set<int> visited;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int oranges = q.front();
                q.pop();
                if (oranges == 0) return days;
                if (oranges - 1 >= 0 && !visited.count(oranges - 1)) {
                    q.push(oranges - 1);
                    visited.insert(oranges - 1);
                }
                if (oranges % 2 == 0 && oranges / 2 >= 0 && !visited.count(oranges / 2)) {
                    q.push(oranges / 2);
                    visited.insert(oranges / 2);
                }
                if (oranges % 3 == 0 && oranges - 2 * (oranges / 3) >= 0 && !visited.count(oranges - 2 * (oranges / 3))) {
                    q.push(oranges - 2 * (oranges / 3));
                    visited.insert(oranges - 2 * (oranges / 3));
                }
            }
            days++;
        }
        return days;
    }
};
